var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"먼 길까지 고생이 많았네. 자네가 발렌티누스 수도원에서 파견된 수녀인가?","JPN":"遠路はるばるご苦労だった。君がバレンチヌス修道院から派遣されたシスターかね？","ENG":"You've come a long way. You must be the nun sent from the Valentinus Monastery.","TWN":"一路上辛苦了。你是聖華倫修道院派來的修女嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네. 루시아 릿지라고 합니다.","JPN":"はい。ルシア・リッジです。","ENG":"Yes. My name is Lucia Ridge.","TWN":"是的，我叫露西卡·李奇。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"표정이 많이 좋지 않군. 혹시 뭔가 불편한 점이 있다면…….","JPN":"浮かない顔だな。もし何か気に入らないことがあるなら……","ENG":"You look upset. Is something bothering you?","TWN":"你的表情看起來不太好。如果有什麼不舒服的地方……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아하하. 그럴 리가요.","JPN":"あはは、そんな。","ENG":"Ahaha, of course not.","TWN":"哈哈，怎麼可能。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"생각해 보면, 푯값도 이 아저씨가 다 내줬어야 하는 거 아냐?","JPN":"考えてみたら交通費もこのおっさんが全部出すべきだろ？","ENG":"Now that I think about it, shouldn't this guy have covered my travel expenses too?","TWN":"仔細想想，這個大叔應該幫我付咖啡錢吧？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"게다가 이 다 무너져가는 카페는 뭐냐고!","JPN":"それに、このボロボロのカフェはなんだよ！","ENG":"And what is up with this run-down cafe?!","TWN":"而且這家快要倒閉的咖啡廳是怎麼回事啊！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이건 전형적인 돈 안 내고 뻐기다가 잠수타는 패턴이잖아!","JPN":"こいつは金を払わずにゴネて、行方をくらます典型的なパターンじゃねえか！","ENG":"This is exactly how people ghost you after dodging a payment!","TWN":"這不就是典型的詐騙手法嗎？先假裝有錢，等你上鉤後再捲款潛逃！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저택까지 있는 대부호라더니, 사실 다 압류 상태인 거 아냐?","JPN":"邸宅まで持ってる大富豪って言ってるけど、実は全部差し押さえられてるとか？","ENG":"A noble with a mansion, huh? What if all his assets have already been seized?","TWN":"說是擁有豪宅的大富翁，其實所有財產都被查封了吧？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"루드윅 형제님의 고통을 하루라도 빨리 해결하지 못해 아픈 마음이 얼굴에 드러난 모양입니다.","JPN":"ブラザー・ルードヴィヒの苦痛を一日でも早く解決したいのに、そうできない苦しみが顔に出たようです。","ENG":"It seems my sorrow for not being able to ease your suffering sooner is showing on my face.","TWN":"想到沒能儘快解決你的痛苦，我的心甚是難過啊。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"오늘은 신께 고해성사를 올려야겠군요.","JPN":"今日は神に告解しなければなりませんね。","ENG":"I'll have to confess my sins today.","TWN":"今天得向主認真的懺悔了。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"일찍이 형제님의 고통을 헤아리지 못한 죄를 저질렀으니까.","JPN":"早くにブラザーの苦痛に気づけなかったという罪を犯したのですから。","ENG":"After all, it would be wrong not to repent for failing to see your pain earlier.","TWN":"因為我曾經犯下了未能體諒你痛苦的罪過。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"뭘 그렇게까지.","JPN":"何もそこまで。","ENG":"That's a bit much.","TWN":"是也沒必要這樣。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그간 별장에서 지내고 있었으니, 이곳 사정을 몰랐던 것뿐이네.","JPN":"今まで別荘で暮らしていたせいで、ここの事情に詳しくなかっただけだ。","ENG":"I've been staying at my villa, so I wasn't aware of the situation in town.","TWN":"因為一直住在別墅，所以不知道這裡的情況。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"별장……? 실례지만 집을 몇 채씩 갖고 계신 건가요?","JPN":"別荘……？　失礼ですが、家を何軒所有していらっしゃるのですか？","ENG":"A villa...? Pardon me, but just how many houses do you own?","TWN":"別墅……？不好意思，你有幾套房子啊？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"집은 재무관리사를 통해 관리하고 있어서 잘 모르겠군.","JPN":"家は財務管理士を通じて管理しているから、よくわからないな。","ENG":"I wouldn't know. My financial manager handles all of them.","TWN":"房子是會計師在管理的，所以我不太清楚。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"지금이라도 물어보면 되겠나?","JPN":"今からでも聞いてみた方がいいのかね？","ENG":"I can ask if you'd like?","TWN":"現在問還來得及嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아뇨. 딱 제가 원하는 대답이었습니다. 형제님.","JPN":"いいえ。私が望んでいた答えでした、ブラザー。","ENG":"No need. That was exactly the answer I wanted to hear, brother.","TWN":"不，這正是我想要的回答。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"본론부터 이야기하지.","JPN":"本題から話そう。","ENG":"Let's get to the point.","TWN":"直接說重點吧。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"지하 묘지에서 선조들이 일어나 영지를 망가뜨리고 있네.","JPN":"地下の墓地で先祖たちが起き上がり、領地を荒らしている。","ENG":"Ancestors have risen from the underground cemetery and are wreaking havoc on my lands.","TWN":"地下墓地裡的祖先復活了，他們正在破壞領地。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"선조들이 일어났다…… 아주 흥미로운 심령 현상이네요.","JPN":"先祖たちが起き上がったと……とても興味深い心霊現象ですね。","ENG":"Ancestors rising from the dead... now that's an interesting ghost story.","TWN":"祖先甦醒了……真是有趣的靈異現象啊。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나도 저택 관리인에게 들은 내용이네.","JPN":"私も邸宅の管理人から聞いた話だ。","ENG":"That's what my estate caretaker reported.","TWN":"我也是從管家那裡聽說的。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"밤만 되면 정체불명의 소리가 들려 지하로 가니 선조들이 나타났다더군.","JPN":"夜になると正体不明の音が聞こえて地下に行ったところ、先祖たちが現れたそうだ。","ENG":"Apparently, every night, strange noises echo from below, and when they go to check, they see the ancestors there.","TWN":"一到晚上就會聽到莫名的聲音，到了地下看到祖先出現在眼前。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"일로 인한 스트레스로 생각해 휴가를 보냈네만, 영 찝찝해서 말이지.","JPN":"仕事によるストレスだと思い休暇を出してやったのだが、どうも気になってね。","ENG":"I figured it was just work-related stress and gave them time off, but something about it still doesn't sit right with me.","TWN":"雖然我正在休假，但總覺得心裡怪怪的。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……후, 후후.","JPN":"……ふ、ふふ。","ENG":"...Ha, haha...","TWN":"……呵，呵呵。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"정말 잘 찾아오셨습니다. 루드윅 형제님.","JPN":"本当によく依頼してくださいました、ブラザー・ルードヴィヒ。","ENG":"Brother Ludwig, you've come to the right place.","TWN":"那你真是找對人了，路易弟兄。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저희, 발렌티누스 수도원은 이런 심령 현상을 전문으로 취급하거든요.","JPN":"バレンチヌス修道院は、このような心霊現象を専門的に扱っています。","ENG":"At the Valentinus Monastery, dealing with cases like these is our specialty.","TWN":"我們聖華倫修道院，專門處理這種靈異現象。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"혹시나 해서 여쭙는 건데, 다른 분들에게 먼저 이 일을 맡기지는 않으셨지요?","JPN":"念のため伺いますが、先にどなたかにこの仕事を任せたことは？","ENG":"Just to be sure, you didn't hire anyone else for this before coming to us, did you?","TWN":"我順便問下，你沒有把這件事交給其他人吧？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어중이떠중이가 덜컥 맡았다가는 악령이 화가 날 수가 있어서요.","JPN":"素人が解決しようとして、逆に悪霊を怒らせる可能性がありますので。","ENG":"If some random amateurs tried to handle this, the evil spirits could get angry.","TWN":"如果讓不知情的人貿然接手，惡靈可能會發怒。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"수소문 끝에 발렌티누스 수도원이 이런 일의 전문가라는 사실을 알게 됐네.","JPN":"あちこち聞いてみて、バレンチヌス修道院がこの類の専門家だということを知った。","ENG":"After some searching, I found out the Valentinus Monastery has the best expertise in matters like these.","TWN":"打聽之後才知道，聖華倫修道院是處理這種事情的專家。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네가 아니면 누가 이 일을 믿고 맡길 수 있겠나?","JPN":"君以外の誰にこんな仕事を任せられる？","ENG":"Who else could I possibly trust with this job if not you?","TWN":"除了你以外，我還能找誰來處理呢？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"루시아 자매?","JPN":"シスター・ルシア？","ENG":"Sister Lucia?","TWN":"露西卡姐妹？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"호구 하나…… 아니, 감정이 북받쳐서.","JPN":"バカが1人……いいえ、感情がこみ上げてきたので。","ENG":"Jackpot– I mean, I'm just a little emotional right now.","TWN":"盤子……不，不好意思，我情緒有點激動。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠시 화장실 좀 갔다 와도 될까요?","JPN":"しばしお手洗いに行ってきてもよろしいですか？","ENG":"May I go to the bathroom for a moment?","TWN":"我能去趟廁所嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"진짜 제대로 호구 잡았잖아?","JPN":"こんな都合のいいカモがいていいの？","ENG":"I really hit the jackpot this time.","TWN":"這真是釣到大魚咧。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"확실하지도 않은 목격담만으로 날 부르다니.","JPN":"確実でもない目撃情報だけで私を呼ぶなんて。","ENG":"Calling me in over some half-baked rumors?","TWN":"竟然只是打聽過而已就把我找來。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈이 많아서 그런가, 그냥 방역 정도로 여기는 거 아냐?","JPN":"金持ちだからか？　大雑把すぎると思うけどな。","ENG":"Does he have so much money that he treats this like pest control?","TWN":"是不是因為錢多，花點小錢做做樣子也無所謂？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잘 됐어. 이참에 잔뜩 벗겨 먹여야지.","JPN":"まあ、いいさ。この機会にたっぷりぼったくってやる。","ENG":"Perfect. I'll milk this opportunity for all it's worth.","TWN":"很好，這次要狠狠地削他一筆。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만…… 침식학 권위자였다면서?","JPN":"でも……侵食学の権威者だったんだろ？","ENG":"But still... wasn't he supposed to be a Corruption expert?","TWN":"但是……他不是侵蝕學的權威嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"조금만 현장을 살펴봤으면 가벼운 침식 재난이라는 걸 알 수 있었을 텐데.","JPN":"現場を少しでも見ていたら軽い侵食災害ってわかるはずなのに。","ENG":"If he had taken a proper look, he would've realized this is just a minor Corruption disaster.","TWN":"稍微查看一下現場就能知道這是輕微的侵蝕災難吧？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그, 그래. 침식 증후군 때문에 치매에 걸린 거야.","JPN":"そ、そうだ。侵食症候群でボケちゃったんだ。","ENG":"Y-yeah. Maybe he has dementia from the Corruption Syndrome.","TWN":"有可能是因為侵蝕症候群導致的癡呆。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"정신이 오락가락하니까 덜컥 일을 맡긴 거지.","JPN":"精神が不安定だから、適当に仕事を依頼してしまったんだ。","ENG":"His mind is slipping, so he ended up handing me the job.","TWN":"因為精神恍惚，所以才突然把事情交給我。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이건 둘도 없는 기회야. 일확천금의 기회라고.","JPN":"これはまたとないチャンスだ。一攫千金のチャンス。","ENG":"This is a golden opportunity. A once-in-a-lifetime windfall.","TWN":"這是千載難逢的機會，是一夕暴富的機會。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……그런 것 치곤 멀쩡해 보이는 건 좀 걸리지만.","JPN":"……その割には元気そうなのがちょっと気にかかるけど。","ENG":"...Though, the fact that he seems fine is a little suspicious.","TWN":"……雖然看起來沒什麼問題，但還是有點在意。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그냥 묘지 어딘가 박혀 있을 침식 쐐기를 없애고, 돈을 뜯어내면 돼.","JPN":"墓地のどこかに刺さっている侵食楔を除去して、金を巻き上げればいい。","ENG":"Whatever. I'll just find the Corrupted Wedge buried somewhere in that cemetery, get rid of it, and collect my payday.","TWN":"總之就是處理掉埋在墓地裡的侵蝕釘，然後找他要錢。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"멀리 계신 우리 아그네스 아비게일 자매님. 보고 계시죠?","JPN":"遠くにいるシスター・アグネス・アビゲイル。見てますよね？","ENG":"Our dear Sister Agnes Abigail, I know you're watching.","TWN":"遠在他方的艾格妮絲·亞比該姐妹。你在看嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저, 꼭 해낼게요.","JPN":"私、絶対やり遂げますから。","ENG":"I won't let you down.","TWN":"我一定會做到的。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이번에 크게 한탕 뛰고, 한동안은 병 연구에 집중할 수 있을 테니까.","JPN":"今回の大仕事でしばらくは病気の研究に集中できるはずだし。","ENG":"This is my big break. After this, I can finally focus on my sickness research for a while.","TWN":"這次大幹一場後，應該能專心研究病症一段時間了。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};